INSERT INTO `conversations` VALUES (19,'29a5a228-666b-11f1-b12b-00155d0557c7','קניית אופנוע - טיפים ורצונות','2026-06-12 17:29:47'),(20,'2c1673cc-666b-11f1-b12b-00155d0557c7','קניית אופנוע חדשה','2026-06-12 17:29:51'),(23,'50ff978c-675c-11f1-b12b-00155d0557c7','מים הדרושים לעץ מנגו','2026-06-13 22:16:01'),(24,'ef0be018-675d-11f1-b12b-00155d0557c7','זמני כניסת שבת בלוח שנה','2026-06-13 22:27:36'),(25,'2b2f9734-6761-11f1-b12b-00155d0557c7','הכנת שניצלים','2026-06-13 22:50:45'),(26,'42f601e3-68e7-11f1-b12b-00155d0557c7','שלום! איך אפשר לעזור לך היום?','2026-06-15 21:23:09'),(27,'a678d0f2-69bb-11f1-b12b-00155d0557c7','השיטה המוצלחת ביותר ללמוד אנגלית','2026-06-16 22:43:29'),(28,'fd0bafa5-69bb-11f1-b12b-00155d0557c7','חומרי לימוד לאנגלית','2026-06-16 22:45:55'),(29,'3e5fa2df-69bd-11f1-b12b-00155d0557c7','אתרים מומלצים בתאילנד','2026-06-16 22:54:54');
